mapper.select:
SELECT
    COUNT(tlal.user) AS pv,
    COUNT(DISTINCT tlal.user) AS uv,
    COUNT(DISTINCT tlal.ip) AS uip
FROM
    t_link tl INNER JOIN
    t_link_access_logs tlal ON tl.full_short_url = tlal.full_short_url
WHERE
    tlal.full_short_url = #{fullShortUrl}
  AND tl.gid = #{gid}
  AND tl.del_flag = '0'
  AND tl.enable_status = '0'
  AND tlal.create_time >= #{startDate}
  AND tlal.create_time < #{endDate}
GROUP BY
    tlal.full_short_url, tl.gid;

SELECT tlal.user, CASE WHEN MIN(tlal.create_time) >= #{arg3} AND MIN(tlal.create_time) < #{arg4} THEN '新访客' ELSE '老访客' END AS uvType FROM t_link tl INNER JOIN t_link_access_logs tlal ON tl.full_short_url = tlal.full_short_url WHERE tlal.full_short_url = #{arg1} AND tl.gid = #{arg0} AND tl.del_flag = '0' AND tl.enable_status = #{arg2} AND tlal.user IN
#{item}
GROUP BY tlal.user;
